def calcular_peso_herrajes(ancho, alto, paneles):
    ancho_base = obtener_ancho_base(ancho)

    total_paneles = sum(paneles.values())

    tabla_ancho = PESO_HERRAJES.get(ancho_base, {})
    tabla_panel = tabla_ancho.get(total_paneles, {})

    for alto_max, peso in sorted(tabla_panel.items()):
        if alto <= alto_max:
            return peso

    return 0


